import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class ChessAgentService {
  private baseUrl = 'http://localhost:8000';

  constructor(private http: HttpClient) {}

  // Correspond à @app.post("/api/v1/analyze-position")
  analyzePosition(fen: string): Observable<any> {
    return this.http.post(`${this.baseUrl}/api/v1/analyze-position`, { fen: fen });
  }

  // Correspond à @app.post("/api/v1/chat")
  // Le backend attend une clé 'prompt'
  sendChatMessage(message: string, fen: string): Observable<any> {
    return this.http.post(`${this.baseUrl}/api/v1/chat`, { prompt: message });
  }
}
